// parseClaudeStream reads newline-delimited claude stream-json events from r,
// writes translated progress entries to progressLog, and returns an aggregated
// claudeStreamResult covering token usage, final text, and counts.
//
// The progress entries use the same event type names the Fizeau harness
// emits (session.start, llm.response, tool.call, tool.result) so the existing
// TailSessionLogs / FormatSessionLogLines pipeline can render them as
// real-time progress without any changes.
//
// beadID and startTime are optional: when provided, each progress entry
// receives a data.bead_id and data.elapsed_ms field for cross-referencing.
//
// progressLog may be nil; if nil, progress entries are discarded but the
// aggregate result is still returned.
func parseClaudeStream(r io.Reader, progressLog io.Writer, sessionID, beadID string, startTime time.Time) (*claudeStreamResult, error) {
	if startTime.IsZero() {
		startTime = time.Now()
	}
	verbose := os.Getenv("DDX_LOG_VERBOSE") == "1"
	pendingTools := map[string]*pendingToolCall{}
	res := &claudeStreamResult{SessionID: sessionID}
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 256*1024), 16*1024*1024) // 16MB max line — claude can dump big tool results

	seq := 0
	emit := func(evType, dataJSON string) {
		if progressLog == nil {
			return
		}
		entry := map[string]any{
			"session_id": sessionID,
			"seq":        seq,
			"type":       evType,
			"ts":         time.Now().UTC().Format(time.RFC3339Nano),
			"data":       json.RawMessage(dataJSON),
		}
		seq++
		line, err := json.Marshal(entry)
		if err != nil {
			return
		}
		_, _ = progressLog.Write(line)
		_, _ = progressLog.Write([]byte("\n"))
	}

	wroteStart := false
	// lastRequestSentAt tracks when the most recent LLM request was sent.
	// For the first turn it equals startTime (the session began with a
	// request). After every "user" event (tool_result returned to the model)
	// we reset it: the next assistant event represents a new round-trip.
	// Per-call latency is then `now - lastRequestSentAt`, distinct from
	// cumulative elapsed_ms.
	lastRequestSentAt := startTime
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		var ev claudeStreamEvent
		if err := json.Unmarshal([]byte(line), &ev); err != nil {
			// Not a JSON event — skip silently to be lenient.
			continue
		}

		now := time.Now()
		elapsedMS := now.Sub(startTime).Milliseconds()
		switch ev.Type {
		case "system":
			if ev.Subtype == "init" && !wroteStart {
				wroteStart = true
				if ev.Model != "" {
					res.Model = ev.Model
				}
				if ev.SessionID != "" {
					res.SessionID = ev.SessionID
				}
				data, _ := json.Marshal(map[string]any{
					"model":      res.Model,
					"session_id": res.SessionID,
					"bead_id":    beadID,
					"elapsed_ms": elapsedMS,
					"harness":    "claude",
				})
				emit("session.start", string(data))
			}

		case "assistant":
			var msg claudeAssistantMessage
			if len(ev.Message) > 0 {
				_ = json.Unmarshal(ev.Message, &msg)
			}
			if msg.Model != "" && res.Model == "" {
				res.Model = msg.Model
			}
			// Running usage totals so TailSessionLogs has the latest view.
			if msg.Usage.InputTokens > 0 {
				res.InputTokens = msg.Usage.InputTokens
			}
			if msg.Usage.OutputTokens > 0 {
				res.OutputTokens = msg.Usage.OutputTokens
			}

			// Count each assistant message as one turn for operator visibility.
			res.TurnCount++

			// Collect tool-use names emitted in this turn, so we can translate
			// the assistant event into an llm.response-like progress entry.
			var toolNames []map[string]string
			var textOut strings.Builder
			var responseBytes, thinkingBytes, toolInputBytes int
			for _, block := range msg.Content {
				switch block.Type {
				case "text":
					if block.Text != "" {
						if textOut.Len() > 0 {
							textOut.WriteString("\n")
						}
						textOut.WriteString(block.Text)
						responseBytes += len([]byte(block.Text))
					}
				case "thinking":
					if block.Thinking != "" {
						thinkingBytes += len([]byte(block.Thinking))
					}
				case "tool_use":
					name := block.Name
					if name == "" {
						name = "tool"
					}
					toolNames = append(toolNames, map[string]string{"name": name})
					toolInputBytes += len(block.Input)
				}
			}

			latencyMS := now.Sub(lastRequestSentAt).Milliseconds()
			if latencyMS < 0 {
				latencyMS = 0
			}
			llmData := map[string]any{
				"model":            res.Model,
				"latency_ms":       latencyMS,
				"tool_calls":       toolNames,
				"turn":             res.TurnCount,
				"bead_id":          beadID,
				"elapsed_ms":       elapsedMS,
				"input_tokens":     res.InputTokens,
				"output_tokens":    res.OutputTokens,
				"response_bytes":   responseBytes,
				"thinking_bytes":   thinkingBytes,
				"tool_input_bytes": toolInputBytes,
				"attempt": map[string]any{
					"cost": map[string]any{
						"raw": map[string]any{
							"total_tokens": res.InputTokens + res.OutputTokens,
						},

		}
	}
	return final, routing, routingPower, progress
}

				}
			}
		}
	}
	return ch, unsub
}

// readActiveSessionLog reads the latest session log entries for an active worker.
// The Fizeau library writes per-iteration entries to .ddx/agent-logs/agent-*.jsonl
// in real-time, so this gives live visibility into what the model provider is doing.
func (m *WorkerManager) readActiveSessionLog(handle *workerHandle) string {
	logDir := filepath.Join(m.projectRoot, ".ddx", "agent-logs")
	entries, err := os.ReadDir(logDir)
	if err != nil {
		return ""
	}

	// Find the most recent agent-*.jsonl file that was modified in the last 30 minutes
	var newest string
	var newestMod time.Time
	cutoff := time.Now().Add(-30 * time.Minute)
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-") || !strings.HasSuffix(entry.Name(), ".jsonl") {
			continue
		}
		// Skip loop event files — they contain loop milestones, not agent session
		// entries. Loop milestone progress is already captured in worker.log.
		if strings.HasPrefix(entry.Name(), "agent-loop-") {
			continue
		}
		info, err := entry.Info()
		if err != nil {
			continue
		}
		if info.ModTime().After(newestMod) && info.ModTime().After(cutoff) {
			newest = filepath.Join(logDir, entry.Name())
			newestMod = info.ModTime()
		}
	}
	if newest == "" {
		return ""
	}

	// Read the last N lines of the session log and format them as readable progress
	data, err := os.ReadFile(newest)
	if err != nil {
		return ""
	}

	lines := strings.Split(strings.TrimSpace(string(data)), "\n")
	// Show the last 50 entries
	start := 0
	if len(lines) > 50 {
		start = len(lines) - 50
	}

	return formatActiveSessionLogLines(lines[start:])
}

func formatActiveSessionLogLines(lines []string) string {
	var progress []agentlib.ServiceProgressData
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry map[string]any
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			continue
		}
		if typ, _ := entry["type"].(string); typ != agentlib.ServiceEventTypeProgress {
			continue
		}
		var data agentlib.ServiceProgressData
		rawData, err := json.Marshal(entry["data"])
		if err != nil {
			continue
		}
		if err := json.Unmarshal(rawData, &data); err != nil {
			continue
		}
		progress = append(progress, data)
	}
	if len(progress) > 0 {
		return agent.FormatServiceProgressEntries(progress)
	}
	return agent.FormatSessionLogLines(lines)
}

// buildPreClaimHook returns a PreClaimHook function that fetches origin and
// verifies ancestry before each bead claim. It resolves the target branch at
// call time via LandingGitOps.CurrentBranch so detached-HEAD and non-main
// trunks are handled correctly.
func buildPreClaimHook(projectRoot string, gitOps agent.LandingGitOps) func(ctx context.Context) error {
	return func(ctx context.Context) error {
		branch, err := gitOps.CurrentBranch(projectRoot)
		if err != nil {
			// Can't determine branch — skip rather than block.
			return nil
		}
		res, err := gitOps.FetchOriginAncestryCheck(projectRoot, branch)
		if err != nil {
			// Fetch failure is non-fatal (air-gap friendly); skip the check.
			return nil
		}
		if res.Action == "diverged" {
			return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
				branch, res.LocalSHA, res.OriginSHA)
		}
		return nil
	}
}

func (m *WorkerManager) writeRecord(dir string, record WorkerRecord) error {
	if record.Status == "" {
		record.Status = record.State
	}
	record.PIDAlive = nil // computed field; never persisted
	data, err := json.MarshalIndent(record, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(filepath.Join(dir, "status.json"), append(data, '\n'), 0o644)
}

func (m *WorkerManager) readRecord(dir string) (WorkerRecord, error) {
	data, err := os.ReadFile(filepath.Join(dir, "status.json"))
	if err != nil {
		return WorkerRecord{}, err
	}
	var record WorkerRecord
	if err := json.Unmarshal(data, &record); err != nil {
		return WorkerRecord{}, err
	}
	if record.Status == "" {
		record.Status = record.State
	}
	return record, nil
}

