func TestWorkerManagerStartAndShow(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	m := NewWorkerManager(root)

	record, err := m.StartExecuteLoop(ExecuteLoopWorkerSpec{
		Harness:  "agent",
		Model:    "qwen/qwen3.6",
		Provider: "openrouter",
		Once:     true,
	})
	require.NoError(t, err)
