	require.NoError(t, os.WriteFile(svcPath, []byte(mustSessionLogLine(t, "progress", map[string]any{
		"phase":   "route",
		"state":   "start",
		"message": "route codex/gpt-5.4-mini power=8 speed=35.5 cost=catalog",
	})+"\n"), 0o644))

