748	func compactPathToken(token string, limit int) string {
749		if limit <= 0 || len(token) <= limit || !strings.Contains(token, "/") {
750			return token
751		}
752		prefix, suffix := splitTokenAffixes(token)
753		core := strings.TrimPrefix(strings.TrimSuffix(token, suffix), prefix)
754		if len(core) <= limit || !strings.Contains(core, "/") {
755			return token
756		}
757		parts := strings.Split(core, "/")
758		last := parts[len(parts)-1]
759		if last == "" && len(parts) > 1 {
760			last = parts[len(parts)-2] + "/"
761		}
762		if last == "" {
763			return truncateStr(token, limit)
764		}
765		compacted := "…/" + last
766		if len(prefix)+len(compacted)+len(suffix) <= limit {
767			return prefix + compacted + suffix
768		}
769		return prefix + truncateStr(compacted, maxInt(1, limit-len(prefix)-len(suffix))) + suffix
770	}
771	
772	func splitTokenAffixes(token string) (string, string) {
773		prefix := ""
774		suffix := ""
775		for len(token) > len(prefix) {
776			switch token[len(prefix)] {
777			case '\'', '"', '`', '(', '[', '{':
778				prefix += string(token[len(prefix)])
779			default:
780				goto suffixLoop
781			}
782		}
783	suffixLoop:
784		for len(token) > len(prefix)+len(suffix) {
785			switch token[len(token)-len(suffix)-1] {
786			case '\'', '"', '`', ')', ']', '}', ',', ';':
787				suffix = string(token[len(token)-len(suffix)-1]) + suffix
788			default:
789				return prefix, suffix
790			}
791		}
792		return prefix, suffix
793	}
