			display = compactProgressToolDisplay(data, toolName, command, 80)
		}
		line := "ok"
		if display != "" {
			line += " " + display
		}
		if outputSummary != "" {
			line += " < " + outputSummary
		}
		suffix := ""
		if duration != "" {
			suffix = " " + duration
		}
		if tokens > 0 {
			suffix += fmt.Sprintf(" %dtok", tokens)
		}
		if throughput := progressThroughputText(data, tokens); throughput != "" {
